args.sparql:
SELECT ?awardLabel WHERE {
  wd:Q1649612 p:P166 ?award_statement.
  ?award_statement ps:P166 ?award.
  ?award rdfs:label ?awardLabel.
  FILTER (LANG(?awardLabel) = 'en' && CONTAINS(STR(?awardLabel), 'Saturn'))
} LIMIT 1

SELECT ?awardLabel WHERE {
  wd:Q1649612 wdt:P166 ?award.
  ?award rdfs:label ?awardLabel.
  FILTER (LANG(?awardLabel) = 'en')
} LIMIT 1
